# Solution

The solution is to pass `router` as a parameter and not to import it as a module.

Example code
```js

// utils/helpers.ts

import { NextRouter } from 'next/router'; // for type

export const nextRouterPushBrowser = (
  target: string,
  router: NextRouter,
  as?: URL | undefined,
  shallow?: boolean
): void => {
  router.push(target, as ?? undefined, { shallow: shallow ?? false });
};
```

```js

// SomeComponent.tsx

import { useRouter } from 'next/router';
import { Button, Text } from '@chakra-ui/react';
import { nextRouterPushBrowser } from '../utils/helpers';

export const Index: React.FC = () => {
  const router = useRouter();

  return (
    <Button onClick={() => nextRouterPushBrowser ('/', router)}>
        <Text>
            Redirect to home
        </Text>
      </Button>
  );
};

export default Index;
```

